// WRONG: race condition — nhiều threads gọi factory cùng lúc
var data = await _cache.GetOrCreateAsync("key", async _ => await FetchFromDbAsync());

// RIGHT: Lazy<Task> pattern để serialize concurrent misses
private readonly ConcurrentDictionary<string, Lazy<Task<Data?>>> _pending = new();

public async Task<Data?> GetWithStampedeProtectionAsync(string key, CancellationToken ct)
{
    if (_cache.TryGetValue<Data>(key, out var cached)) return cached;

    var lazy = _pending.GetOrAdd(key, _ => new Lazy<Task<Data?>>(() =>
        FetchAndCacheAsync(key, ct)));
    try { return await lazy.Value; }
    finally { _pending.TryRemove(key, out _); }
}

private async Task<Data?> FetchAndCacheAsync(string key, CancellationToken ct)
{
    var data = await FetchFromDbAsync(key, ct);
    var options = new MemoryCacheEntryOptions()
        .SetAbsoluteExpiration(TimeSpan.FromMinutes(5))
        .SetSize(1)                           // cần thiết khi có SizeLimit
        .RegisterPostEvictionCallback((k, v, r, s) =>
            _logger.LogDebug("Cache evicted {Key}: {Reason}", k, r));
    return _cache.Set(key, data, options);
}

// Config với SizeLimit (bytes or custom units)
builder.Services.AddMemoryCache(opt =>
{
